#!/bin/bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-05-03

# Unit tests for /ork:dev boot.sh helpers introduced in M127.
# Tests fixture-based behavior of is_monorepo, json_render_adapter, has_clerk
# and verifies the Clerk mapping in dep-to-emulator-map.json.
#
# Sourcing model: boot.sh has a BASH_SOURCE guard that skips main() when
# sourced. This file sources boot.sh once, then drives helpers against
# temp PROJECT_DIR fixtures.

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="$(cd "${SCRIPT_DIR}/../.." && pwd)"
BOOT_SH="${PROJECT_ROOT}/src/skills/dev/scripts/boot.sh"
DEP_MAP="${PROJECT_ROOT}/src/skills/emulate-seed/references/dep-to-emulator-map.json"

RED='\033[0;31m'
GREEN='\033[0;32m'
NC='\033[0m'

TESTS_PASSED=0
TESTS_FAILED=0
FAILED_NAMES=()

log_pass() { echo -e "${GREEN}✓${NC} $1"; TESTS_PASSED=$((TESTS_PASSED + 1)); }
log_fail() { echo -e "${RED}✗${NC} $1"; TESTS_FAILED=$((TESTS_FAILED + 1)); FAILED_NAMES+=("$1"); }

# ── Source boot.sh helpers ──────────────────────────────────────────────────
if [[ ! -f "${BOOT_SH}" ]]; then
  echo "FATAL: boot.sh missing at ${BOOT_SH}" >&2
  exit 1
fi
# shellcheck source=/dev/null
source "${BOOT_SH}"

# ── Fixture helpers ─────────────────────────────────────────────────────────
TMP_BASE="$(mktemp -d)"
trap 'rm -rf "${TMP_BASE}"' EXIT

new_fixture() {
  local name="$1"
  local dir="${TMP_BASE}/${name}"
  mkdir -p "${dir}"
  printf '%s' "${dir}"
}

write_pkg_json() {
  local dir="$1"
  local content="$2"
  printf '%s' "${content}" > "${dir}/package.json"
}

# ── is_monorepo() tests ─────────────────────────────────────────────────────

test_is_monorepo_turbo_json() {
  local dir; dir=$(new_fixture turbo)
  echo '{}' > "${dir}/turbo.json"
  PROJECT_DIR="${dir}" is_monorepo \
    && log_pass "is_monorepo: detects turbo.json" \
    || log_fail "is_monorepo: turbo.json"
}

test_is_monorepo_workspaces_array() {
  local dir; dir=$(new_fixture ws-array)
