# ── dep-to-emulator-map.json: Clerk mapping ─────────────────────────────────

test_dep_map_has_clerk_entry() {
  if ! command -v jq >/dev/null 2>&1; then
    log_fail "dep_map: jq not installed (skipping)"
    return
  fi
  local count
  count=$(jq '[.mappings[] | select(.emulators | index("clerk"))] | length' "${DEP_MAP}")
  if [[ "${count}" -ge 1 ]]; then
    log_pass "dep-to-emulator-map: clerk emulator mapping present"
  else
    log_fail "dep-to-emulator-map: no clerk mapping"
  fi
}

test_dep_map_clerk_covers_canonical_packages() {
  if ! command -v jq >/dev/null 2>&1; then
    log_fail "dep_map: jq not installed (skipping)"
    return
  fi
  local missing=0
  for pkg in "@clerk/nextjs" "@clerk/clerk-react" "@clerk/backend"; do
    local hit
    hit=$(jq --arg p "${pkg}" '[.mappings[] | select(.deps | index($p)) | select(.emulators | index("clerk"))] | length' "${DEP_MAP}")
    [[ "${hit}" -ge 1 ]] || { log_fail "dep_map: ${pkg} not mapped to clerk"; missing=1; }
  done
  [[ "${missing}" -eq 0 ]] && log_pass "dep-to-emulator-map: covers nextjs / clerk-react / backend"
}

test_dep_map_clerk_has_emulate_version_note() {
  if ! command -v jq >/dev/null 2>&1; then
    log_fail "dep_map: jq not installed (skipping)"
    return
  fi
  # Note must mention 0.5 — readers need to know the upstream version requirement.
  local has_note
  has_note=$(jq -r '
    [.mappings[]
      | select(.emulators | index("clerk"))
      | .note // ""
      | select(test("0\\.5"; "i"))
    ] | length' "${DEP_MAP}")
  if [[ "${has_note}" -ge 1 ]]; then
    log_pass "dep-to-emulator-map: clerk note references emulate 0.5"
  else
    log_fail "dep-to-emulator-map: clerk note missing emulate-version requirement"
  fi
}

# ── auto-discover.sh integration: package.json with @clerk/* → clerk emulator ─

test_auto_discover_emits_clerk() {
  local discover="${PROJECT_ROOT}/src/skills/emulate-seed/scripts/auto-discover.sh"
  if [[ ! -x "${discover}" ]]; then
    log_fail "auto_discover: script not executable at ${discover}"
    return
  fi
  if ! command -v jq >/dev/null 2>&1; then
    log_fail "auto_discover: jq not installed (skipping)"
    return
  fi
  local dir; dir=$(new_fixture autodisc-clerk)
  write_pkg_json "${dir}" '{"dependencies":{"@clerk/nextjs":"5.0.0"}}'
  local out
  out=$(CLAUDE_PROJECT_DIR="${dir}" bash "${discover}" --json 2>&1)
  local emulator_count
  emulator_count=$(printf '%s' "${out}" | jq '[.emulators[]? | select(. == "clerk")] | length')
  if [[ "${emulator_count}" -ge 1 ]]; then
    log_pass "auto-discover: emits clerk emulator for @clerk/nextjs"
  else
    log_fail "auto-discover: did not emit clerk (output: ${out})"
  fi
}

